import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import styled from 'styled-components';

// Styled Components
const DashboardContainer = styled.div`
  min-height: 100vh;
  background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
  padding: 2rem;
`;

const Header = styled.header`
  display: flex;
  justify-content: space-between;
  align-items: center;
  background: rgba(255, 255, 255, 0.1);
  backdrop-filter: blur(10px);
  border-radius: 16px;
  padding: 1rem 2rem;
  margin-bottom: 2rem;
  box-shadow: 0 8px 32px 0 rgba(31, 38, 135, 0.37);
`;

const WelcomeText = styled.div`
  color: white;
  h1 {
    font-size: 1.5rem;
    font-weight: bold;
    margin: 0;
  }
  p {
    margin: 0.5rem 0 0 0;
    opacity: 0.8;
  }
`;

const UserInfo = styled.div`
  display: flex;
  align-items: center;
  gap: 1rem;
`;

const UserAvatar = styled.img`
  width: 40px;
  height: 40px;
  border-radius: 50%;
  border: 2px solid rgba(255, 255, 255, 0.3);
`;

const LogoutButton = styled.button`
  background: rgba(255, 255, 255, 0.2);
  color: white;
  border: 1px solid rgba(255, 255, 255, 0.3);
  padding: 0.5rem 1rem;
  border-radius: 8px;
  cursor: pointer;
  font-weight: 500;
  transition: all 0.2s ease;
  
  &:hover {
    background: rgba(255, 255, 255, 0.3);
    transform: translateY(-1px);
  }
`;

const ContentGrid = styled.div`
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(300px, 1fr));
  gap: 2rem;
  margin-top: 2rem;
`;

const Card = styled.div`
  background: rgba(255, 255, 255, 0.15);
  backdrop-filter: blur(10px);
  border-radius: 16px;
  padding: 2rem;
  box-shadow: 0 8px 32px 0 rgba(31, 38, 135, 0.37);
  border: 1px solid rgba(255, 255, 255, 0.18);
  
  h3 {
    color: white;
    font-size: 1.25rem;
    font-weight: bold;
    margin: 0 0 1rem 0;
  }
  
  p {
    color: rgba(255, 255, 255, 0.8);
    line-height: 1.6;
    margin: 0;
  }
`;

const LoadingSpinner = styled.div`
  display: flex;
  justify-content: center;
  align-items: center;
  height: 200px;
  
  .spinner {
    width: 40px;
    height: 40px;
    border: 4px solid rgba(255, 255, 255, 0.3);
    border-top: 4px solid white;
    border-radius: 50%;
    animation: spin 1s linear infinite;
  }
  
  @keyframes spin {
    0% { transform: rotate(0deg); }
    100% { transform: rotate(360deg); }
  }
`;

const ErrorMessage = styled.div`
  background: rgba(239, 68, 68, 0.2);
  color: white;
  padding: 1rem;
  border-radius: 8px;
  margin: 1rem 0;
  text-align: center;
  border: 1px solid rgba(239, 68, 68, 0.3);
`;

const DashboardPage = () => {
  const navigate = useNavigate();
  const [user, setUser] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');

  useEffect(() => {
    // 🔥 백엔드 연결 포인트 2: 사용자 인증 상태 확인 및 프로필 정보 가져오기
    const checkAuthAndLoadProfile = async () => {
      try {
        const token = localStorage.getItem('accessToken');
        const savedUser = localStorage.getItem('user');
        
        if (!token) {
          // 토큰이 없으면 로그인 페이지로 리다이렉트
          navigate('/login');
          return;
        }

        // 저장된 사용자 정보가 있으면 먼저 표시
        if (savedUser) {
          setUser(JSON.parse(savedUser));
        }

        // 🔥 백엔드 API 호출 - 최신 사용자 정보 가져오기
        const response = await fetch('/api/user/profile', {
          method: 'GET',
          headers: {
            'Authorization': `Bearer ${token}`,
            'Content-Type': 'application/json',
          },
        });

        if (response.status === 401) {
          // 토큰이 만료되었거나 유효하지 않음
          localStorage.removeItem('accessToken');
          localStorage.removeItem('refreshToken');
          localStorage.removeItem('user');
          navigate('/login');
          return;
        }

        const data = await response.json();
        
        if (data.success) {
          setUser(data.user);
          // 최신 정보로 로컬 스토리지 업데이트
          localStorage.setItem('user', JSON.stringify(data.user));
        } else {
          setError('사용자 정보를 불러오는데 실패했습니다.');
        }

      } catch (error) {
        console.error('Profile loading error:', error);
        setError('네트워크 오류가 발생했습니다.');
      } finally {
        setLoading(false);
      }
    };

    checkAuthAndLoadProfile();
  }, [navigate]);

  // 🔥 백엔드 연결 포인트 3: 로그아웃 처리
  const handleLogout = async () => {
    try {
      const token = localStorage.getItem('accessToken');
      
      if (token) {
        // 🔥 백엔드 API 호출 - 서버에서 토큰 무효화
        await fetch('/api/auth/logout', {
          method: 'POST',
          headers: {
            'Authorization': `Bearer ${token}`,
            'Content-Type': 'application/json',
          },
        });
      }
    } catch (error) {
      console.error('Logout error:', error);
      // 에러가 발생해도 로컬 데이터는 삭제
    } finally {
      // 로컬 스토리지 정리
      localStorage.removeItem('accessToken');
      localStorage.removeItem('refreshToken');
      localStorage.removeItem('user');
      
      // 로그인 페이지로 이동
      navigate('/login');
    }
  };

  if (loading) {
    return (
      <DashboardContainer>
        <LoadingSpinner>
          <div className="spinner"></div>
        </LoadingSpinner>
      </DashboardContainer>
    );
  }

  if (error) {
    return (
      <DashboardContainer>
        <ErrorMessage>{error}</ErrorMessage>
      </DashboardContainer>
    );
  }

  return (
    <DashboardContainer>
      <Header>
        <WelcomeText>
          <h1>환영합니다! {user?.name || '사용자'}님</h1>
          <p>대시보드에 오신 것을 환영합니다.</p>
        </WelcomeText>
        
        <UserInfo>
          {user?.picture && (
            <UserAvatar 
              src={user.picture} 
              alt={user.name || '사용자'} 
            />
          )}
          <div style={{ color: 'white' }}>
            <div style={{ fontWeight: 'bold' }}>{user?.name || '이름 없음'}</div>
            <div style={{ fontSize: '0.875rem', opacity: 0.8 }}>
              {user?.email || '이메일 없음'}
            </div>
          </div>
          <LogoutButton onClick={handleLogout}>
            로그아웃
          </LogoutButton>
        </UserInfo>
      </Header>

      <ContentGrid>
        <Card>
          <h3>사용자 정보</h3>
          <p>
            <strong>이름:</strong> {user?.name || 'N/A'}<br/>
            <strong>이메일:</strong> {user?.email || 'N/A'}<br/>
            <strong>가입일:</strong> {user?.createdAt ? new Date(user.createdAt).toLocaleDateString() : 'N/A'}
          </p>
        </Card>

        <Card>
          <h3>최근 활동</h3>
          <p>
            최근 로그인: {new Date().toLocaleString()}<br/>
            활동 점수: 0점<br/>
            완료한 작업: 0개
          </p>
        </Card>

        <Card>
          <h3>설정</h3>
          <p>
            프로필 설정, 알림 설정, 보안 설정 등을 관리할 수 있습니다.
            이 영역은 추후 개발될 예정입니다.
          </p>
        </Card>

        <Card>
          <h3>도움말</h3>
          <p>
            서비스 이용에 도움이 필요하시면 고객지원팀에 문의하세요.
            FAQ와 사용자 가이드도 준비되어 있습니다.
          </p>
        </Card>
      </ContentGrid>
    </DashboardContainer>
  );
};

export default DashboardPage;
